export default function About() {
  return (
    <main className="page">
      <h1>عن المشروع</h1>
      <p>
        مشروع Cairo Traffic يساعد المستخدمين على معرفة حالة المرور، متابعة الأخبار،
        وإرسال التقارير عن المشاكل المرورية داخل القاهرة.
      </p>
    </main>
  );
}
